import React, { useState, useEffect } from 'react';
import axios from 'axios';

const BookingList = () => {
  const [bookings, setBookings] = useState([]);

  useEffect(() => {
    const fetchBookings = async () => {
      const token = localStorage.getItem('adminToken');
      const res = await axios.get('http://localhost:8080/bookings', { headers: { Authorization: `Bearer ${token}` } });
      setBookings(res.data);
    };
    fetchBookings();
  }, []);

  const handleDelete = async (id) => {
    const token = localStorage.getItem('adminToken');
    await axios.delete(`http://localhost:8080/bookings/${id}`, { headers: { Authorization: `Bearer ${token}` } });
    setBookings(bookings.filter(b => b.id !== id));
  };

  // Add update form similarly

  return (
    <ul className="space-y-2">
      {bookings.map(b => (
        <li key={b.id} className="border p-2">
          {b.name} - {b.date} - {b.zone}
          <button onClick={() => handleDelete(b.id)} className="ml-4 bg-red-500 text-white p-1">Delete</button>
        </li>
      ))}
    </ul>
  );
};

export default BookingList;
